(function() {
    /*======== 版本更新日志 ========*/
    /*
     * 作者：sjshb57
     * GitHub：https://github.com/sjshb57/legado-57
     *
     * [v2.8.6] 第三十五次修改 - 优化代码
     * - 新增 assemble() 统一组装函数
     * - 删除 chinesePunctuation 函数
     * - 修复部分类型标题被错误解析的问题
     * - 优化部分代码，修复历史部分功能失效问题
     * - 修复 extraSuffixes 拼接缺少字符转义的问题
     */

    // ========= 1. 功能文档 =========
    /*
     * 功能概述：
     * 本脚本是一个高级中文数字标题转换工具，专门用于处理各种格式的中文数字标题，
     * 将其转换为统一的阿拉伯数字格式，同时提供多种智能处理选项。
     * 
     */

    // ========= 2. 配置系统 =========
    /**
     * 可通过 Config 对象调整以下配置项：
     */
    const Config = {
        punctuationsToRemove: '.。,，、', // 需要统一删除的标点字符集
        convertZeroToPreface: false, // 是否将零值转换为"序"
        defaultSuffix: '章', // 覆盖使用此章节标识后缀
        preserveSuffixes: '卷次' // 白名单：这些标识符不被 defaultSuffix 覆盖，原样保留（空字符串则全部替换）
    };

    // ====== 3. 正则表达式系统 ======
    /*
     * Regex 对象封装所有预编译的正则表达式，避免重复编译，提升性能。
     * 标点相关的正则均根据 Config.punctuationsToRemove 动态构建。
     * chapter / digitalChapterWithSuffix 的标识符字符类由 baseSuffixes + preserveSuffixes
     * 动态合并，每个字符单独转义，防止特殊字符破坏正则字符类。
     */
    var escaped = Config.punctuationsToRemove.replace(/[-\]\\\^[\/.*+?()|{}$]/g, '\\$&');
    var baseSuffixes = '章节回集卷部篇话讲段';
    var extraSuffixes = '';
    for (var si = 0; si < Config.preserveSuffixes.length; si++) {
        var sch = Config.preserveSuffixes.charAt(si);
        var schEscaped = sch.replace(/[-\]\\\^[\/.*+?()|{}$]/g, '\\$&');
        if (baseSuffixes.indexOf(sch) < 0 && extraSuffixes.indexOf(sch) < 0) extraSuffixes += schEscaped;
    }
    var allSuffixes = baseSuffixes + extraSuffixes;
    var Regex = {
        patterns: {
            chapter: new RegExp('^第(\\d+|[零〇一二三四五六七八九十百千两万壹贰叁肆伍陆柒捌玖拾佰仟萬貳參陸]+)([' + allSuffixes + ']?)(.*)'),
            digitalChapterWithSuffix: new RegExp('^(\\d+)([' + allSuffixes + '])(.*)'),
            digitalChapter: /^(\d+)\s*(.*)/,
            allPunctuations: new RegExp('[' + escaped + ']', 'g')
        }
    };

    // 半角→全角标点映射表（仅用于章节号与标题间的分隔字符转换）
    var halfToFull = {
        ':': '：',
        '!': '！',
        '?': '？',
        ',': '，',
        ';': '；',
        '(': '（',
        ')': '）'
    };

    // ======= 4. 数字转换系统 =======
    /*
     * NumberConverter 负责将中文数字字符串转换为阿拉伯数字。
     *
     * map 映射表覆盖：
     *   基础数字：零〇一二两三四五六七八九（含同义词）
     *   单位数字：十百千万（进位单位）
     *   财务大写：壹贰叁肆伍陆柒捌玖拾佰仟萬
     *   繁体数字：貳參陸
     *
     * convert 算法（逐字扫描，O(n) 时间，O(1) 空间）：
     *   维护 total（累计值）和 temp（待与进位单位相乘的临时值）两个变量。
     *   遇到进位单位时 temp 为 0 则视为隐含的 1（如『十二』→ 12），
     *   temp × 单位累加到 total 后归零；遇到普通数字则 temp += 数值。
     */
    const NumberConverter = {
        map: {
            // 基础数字
            '零': 0,
            '〇': 0,
            '一': 1,
            '二': 2,
            '两': 2,
            '三': 3,
            '四': 4,
            '五': 5,
            '六': 6,
            '七': 7,
            '八': 8,
            '九': 9,
            // 进位单位
            '十': 10,
            '百': 100,
            '千': 1000,
            '万': 10000,
            // 财务大写
            '壹': 1,
            '贰': 2,
            '叁': 3,
            '肆': 4,
            '伍': 5,
            '陆': 6,
            '柒': 7,
            '捌': 8,
            '玖': 9,
            '拾': 10,
            '佰': 100,
            '仟': 1000,
            '萬': 10000,
            // 繁体
            '貳': 2,
            '參': 3,
            '陸': 6
        },

        convert: function(chineseNum) {
            var total = 0;
            var temp = 0;

            for (var i = 0; i < chineseNum.length; i++) {
                var val = this.map[chineseNum.charAt(i)]; // Rhino 兼容：用 charAt(i) 替代 [i]
                if (val === 10 || val === 100 || val === 1000 || val === 10000) {
                    temp = (temp === 0 ? 1 : temp) * val;
                    total += temp;
                    temp = 0;
                } else if (val !== undefined) {
                    temp += val;
                }
            }

            return total + temp;
        }
    };

    // ======== 5. 工具函数 ========
    /*
     * assemble()：章节号与标题内容的统一组装函数。
     * 步骤6（数字+标识符分支）与步骤9（第X章分支）共用同一套分隔逻辑。
     *
     * 分隔策略（按优先级）：
     *   1. 半角/全角空格、无分隔、直接是汉字或英文数字 → 补半角空格
     *   2. halfToFull 中的半角标点 → 转换为对应全角标点，直接拼接
     *   3. 其他符号/全角标点 → 原样保留，直接拼接
     */
    function assemble(prefix, suffix, titlePart) {
        var cleanPart = titlePart.replace(/^\s+|\s+$/g, '');
        if (!cleanPart) return prefix + suffix;
        var firstChar = titlePart.charAt(0);
        if (firstChar === ' ' || firstChar === '\u3000' || firstChar === '') {
            // 半角空格、全角空格、或无分隔 → 补半角空格
            return prefix + suffix + ' ' + cleanPart;
        } else if (halfToFull[firstChar]) {
            // 半角标点 → 转全角后直接拼接，内容从第2字符起
            return prefix + suffix + halfToFull[firstChar] + titlePart.slice(1).replace(/^\s+|\s+$/g, '');
        } else if (/[\u4e00-\u9fff\w]/.test(firstChar)) {
            // 直接是汉字或英文数字 → 补半角空格
            return prefix + suffix + ' ' + cleanPart;
        } else {
            // 其他符号（全角标点等）→ 原样保留，直接拼接
            return prefix + suffix + firstChar + titlePart.slice(1).replace(/^\s+|\s+$/g, '');
        }
    }

    // ======== 6. 主处理函数 ========

    function processTitle(title) {

        // --- 步骤1：括号内容处理 ---
        // 含黑名单字符的括号内容整体删除，其余转为「 (内容) 」（半角括号两侧补空格）。
        // 拆为闭合/未闭合两步，避免 g 标志 + $ 锚定的回溯问题。
        var bracketBlacklist = /[票更快祝新迎章订架求免]/;
        title = title.replace(/[（(]([^）)]*)[）)]/g, function(_, inner) {
            return bracketBlacklist.test(inner) ? '' : ' (' + inner + ') ';
        });
        title = title.replace(/[（(]([^）)]*)$/, function(_, inner) {
            return bracketBlacklist.test(inner) ? '' : ' (' + inner + ')';
        });
        title = title.replace(/ {2,}/g, ' ').replace(/^ +| +$/g, '');

        // --- 步骤2：「数字.数字」前缀剥离 ---
        // 处理「8.29 请假条」等日期/编号前缀，识别特征为数字后紧跟「.数字」。
        // 须在步骤3标点清理前判断（步骤3会把「.」删掉），return 前补做标点清理。
        if (/^\d+\.\d/.test(title)) {
            var stripped = title.replace(/^[\d.]+/, '').replace(/^\s+|\s+$/g, '');
            if (stripped) return stripped.replace(Regex.patterns.allPunctuations, '');
        }

        // --- 步骤3：统一标点预处理 ---
        // 对 punctuationsToRemove 中的标点一次性全文删除。
        title = title.replace(Regex.patterns.allPunctuations, '');

        // --- 步骤4：数字+标识符标题处理 ---
        // 处理「29章 请假」等格式，须在步骤5（纯数字）之前判断，
        // 否则「章」字会被误吞入内容，输出「第29章 章 请假」。
        var suffixMatch = title.match(Regex.patterns.digitalChapterWithSuffix);
        if (suffixMatch) {
            var sNum = suffixMatch[1];
            var sOrigSuffix = suffixMatch[2];
            var sTitlePart = suffixMatch[3] || '';
            var sSuffix = (Config.preserveSuffixes.indexOf(sOrigSuffix) >= 0) ?
                sOrigSuffix : Config.defaultSuffix;
            return assemble('第' + sNum, sSuffix, sTitlePart);
        }

        // --- 步骤5：纯数字标题处理 ---
        // 匹配数字开头的标题，统一转换为「第N章 内容」格式。
        var digitalMatch = title.match(Regex.patterns.digitalChapter);
        if (digitalMatch) {
            var num = digitalMatch[1];
            var cleanedContent = digitalMatch[2].replace(/^\s+|\s+$/g, '');
            return cleanedContent ?
                '第' + num + Config.defaultSuffix + ' ' + cleanedContent :
                '第' + num + Config.defaultSuffix;
        }

        // --- 步骤6：非「第」开头标题处理 ---
        // 不以「第」开头则无章节号可转换，直接返回。
        if (title.charAt(0) !== '第') return title;

        // --- 步骤7：正则匹配「第X章」标题各部分 ---
        // 提取 chineseNum（数字）、originalSuffix（标识符）、titlePart（内容）。
        // 匹配失败（如「第abc章」）则原样返回。
        var match = title.match(Regex.patterns.chapter);
        if (!match) return title;

        var chineseNum = match[1];
        var originalSuffix = match[2];
        var titlePart = match[3] || '';

        // 无标识符时，若 titlePart 以时间词开头则原样返回，避免误匹配
        if (!originalSuffix && /^[季年月日周天期次]/.test(titlePart.replace(/^\s+/, ''))) {
            return title;
        }

        // suffix：白名单内标识符原样保留，其余统一使用 defaultSuffix
        var suffix = (originalSuffix && Config.preserveSuffixes.indexOf(originalSuffix) >= 0) ?
            originalSuffix : Config.defaultSuffix;

        // --- 步骤8：数字转换 ---
        // chineseNum 为阿拉伯数字时直接使用，否则调用 NumberConverter.convert 转换。
        var number = /^\d+$/.test(chineseNum) ? chineseNum : NumberConverter.convert(chineseNum);

        // --- 步骤9：零值处理与结果组装 ---
        // Number() 显式转换，避免字符串与 0 严格比较失败。
        if (Number(number) === 0 && Config.convertZeroToPreface) {
            number = '';
            suffix = '序' + suffix;
        }
        return assemble('第' + number, suffix, titlePart);
    }

    // ========== 执行入口 ==========
    // result 是阅读软件传入的原始标题文本，processTitle 处理后返回转换结果。
    return processTitle(result);
})();
